     149: 		markedwp = marked_pane.wp;
     150: 
     151: 		if (lastwp != NULL) {
     152: 			lastwp->flags |= (PANE_REDRAW|PANE_STYLECHANGED|
     153: 			    PANE_THEMECHANGED);
     154: 			server_redraw_window_borders(lastwp->window);
     155: 			server_status_window(lastwp->window);
     156: 		}
     157: 		if (markedwp != NULL) {
     158: 			markedwp->flags |= (PANE_REDRAW|PANE_STYLECHANGED|
     159: 			    PANE_THEMECHANGED);
     160: 			server_redraw_window_borders(markedwp->window);
     161: 			server_status_window(markedwp->window);
     162: 		}
     163: 		return (CMD_RETURN_NORMAL);
     164: 	}
     165: 
     166: 	style = args_get(args, 'P');
