     171: 			return (CMD_RETURN_ERROR);
     172: 		}
>>   173: 		options_set_string(oo, "window-active-style", 0, "%s", style);
     174: 		wp->flags |= (PANE_REDRAW|PANE_STYLECHANGED|PANE_THEMECHANGED);
     175: 	}
     176: 	if (args_has(args, 'g')) {
     177: 		cmdq_print(item, "%s", options_get_string(oo, "window-style"));
     178: 		return (CMD_RETURN_NORMAL);
     179: 	}
     180: 
     181: 	if (args_has(args, 'L')) {
     182: 		window_push_zoom(w, 0, 1);
     183: 		wp = window_pane_find_left(wp);
     184: 		window_pop_zoom(w);
     185: 	} else if (args_has(args, 'R')) {
     186: 		window_push_zoom(w, 0, 1);
     187: 		wp = window_pane_find_right(wp);
     188: 		window_pop_zoom(w);
     189: 	} else if (args_has(args, 'U')) {
     190: 		window_push_zoom(w, 0, 1);
     191: 		wp = window_pane_find_up(wp);
     192: 		window_pop_zoom(w);
