     203: 		server_redraw_window_borders(wp->window);
     204: 		server_status_window(wp->window);
     205: 		return (CMD_RETURN_NORMAL);
     206: 	}
     207: 	if (args_has(args, 'd')) {
     208: 		wp->flags |= PANE_INPUTOFF;
     209: 		server_redraw_window_borders(wp->window);
     210: 		server_status_window(wp->window);
     211: 		return (CMD_RETURN_NORMAL);
     212: 	}
     213: 
     214: 	if (args_has(args, 'T')) {
