     238: 	cmdq_insert_hook(s, item, current, "after-select-pane");
     239: 	cmd_select_pane_redraw(w);
     240: 	if (window_pop_zoom(w))
     241: 		server_redraw_window(w);
     242: 
     243: 	return (CMD_RETURN_NORMAL);
     244: }

