      83: static enum cmd_retval
      84: cmd_set_option_exec(struct cmd *self, struct cmdq_item *item)
      85: {
      86: 	struct args			*args = cmd_get_args(self);
      87: 	int				 append = args_has(args, 'a');
      88: 	struct cmd_find_state		*target = cmdq_get_target(item);
      89: 	struct window_pane		*loop;
      90: 	struct options			*oo;
      91: 	struct options_entry		*parent, *o, *po;
      92: 	char				*name, *argument, *expanded = NULL;
      93: 	char				*cause;
      94: 	const char			*value;
      95: 	int				 window, idx, already, error, ambiguous;
      96: 	int				 scope;
      97: 
      98: 	window = (cmd_get_entry(self) == &cmd_set_window_option_entry);
      99: 
     100: 	/* Expand argument. */
     101: 	argument = format_single_from_target(item, args_string(args, 0));
     102: 
     103: 	/* If set-hook -R, fire the hook straight away. */
     104: 	if (cmd_get_entry(self) == &cmd_set_hook_entry && args_has(args, 'R')) {
     105: 		notify_hook(item, argument);
     106: 		free(argument);
     107: 		return (CMD_RETURN_NORMAL);
     108: 	}
     109: 
     110: 	/* Parse option name and index. */
     111: 	name = options_match(argument, &idx, &ambiguous);
     112: 	if (name == NULL) {
     113: 		if (args_has(args, 'q'))
     114: 			goto out;
     115: 		if (ambiguous)
     116: 			cmdq_error(item, "ambiguous option: %s", argument);
     117: 		else
     118: 			cmdq_error(item, "invalid option: %s", argument);
     119: 		goto fail;
     120: 	}
     121: 	if (args_count(args) < 2)
     122: 		value = NULL;
     123: 	else
     124: 		value = args_string(args, 1);
