     126: 		expanded = format_single_from_target(item, value);
     127: 		value = expanded;
     128: 	}
     129: 
     130: 	/* Get the scope and table for the option .*/
     131: 	scope = options_scope_from_name(args, window, name, target, &oo,
     132: 	    &cause);
     133: 	if (scope == OPTIONS_TABLE_NONE) {
     134: 		if (args_has(args, 'q'))
     135: 			goto out;
     136: 		cmdq_error(item, "%s", cause);
     137: 		free(cause);
     138: 		goto fail;
     139: 	}
     140: 	o = options_get_only(oo, name);
     141: 	parent = options_get(oo, name);
     142: 
     143: 	/* Check that array options and indexes match up. */
     144: 	if (idx != -1 && (*name == '@' || !options_is_array(parent))) {
     145: 		cmdq_error(item, "not an array: %s", argument);
     146: 		goto fail;
     147: 	}
     148: 
     149: 	/* With -o, check this option is not already set. */
     150: 	if (!args_has(args, 'u') && args_has(args, 'o')) {
     151: 		if (idx == -1)
     152: 			already = (o != NULL);
     153: 		else {
     154: 			if (o == NULL)
     155: 				already = 0;
     156: 			else
     157: 				already = (options_array_get(o, idx) != NULL);
     158: 		}
     159: 		if (already) {
     160: 			if (args_has(args, 'q'))
     161: 				goto out;
     162: 			cmdq_error(item, "already set: %s", argument);
     163: 			goto fail;
     164: 		}
     165: 	}
     166: 
     167: 	/* Change the option. */
     168: 	if (args_has(args, 'U') && scope == OPTIONS_TABLE_WINDOW) {
     169: 		TAILQ_FOREACH(loop, &target->w->panes, entry) {
     170: 			po = options_get_only(loop->options, name);
     171: 			if (po == NULL)
     172: 				continue;
     173: 			if (options_remove_or_default(po, idx, &cause) != 0) {
     174: 				cmdq_error(item, "%s", cause);
     175: 				free(cause);
     176: 				goto fail;
     177: 			}
     178: 		}
     179: 	}
     180: 	if (args_has(args, 'u') || args_has(args, 'U')) {
     181: 		if (o == NULL)
     182: 			goto out;
     183: 		if (options_remove_or_default(o, idx, &cause) != 0) {
     184: 			cmdq_error(item, "%s", cause);
     185: 			free(cause);
     186: 			goto fail;
     187: 		}
     188: 	} else if (*name == '@') {
     189: 		if (value == NULL) {
     190: 			cmdq_error(item, "empty value");
     191: 			goto fail;
     192: 		}
>>   193: 		options_set_string(oo, name, append, "%s", value);
     194: 	} else if (idx == -1 && !options_is_array(parent)) {
     195: 		error = options_from_string(oo, options_table_entry(parent),
     196: 		    options_table_entry(parent)->name, value,
     197: 		    args_has(args, 'a'), &cause);
     198: 		if (error != 0) {
     199: 			cmdq_error(item, "%s", cause);
     200: 			free(cause);
     201: 			goto fail;
     202: 		}
     203: 	} else {
     204: 		if (value == NULL) {
     205: 			cmdq_error(item, "empty value");
     206: 			goto fail;
     207: 		}
     208: 		if (o == NULL)
     209: 			o = options_empty(oo, options_table_entry(parent));
     210: 		if (idx == -1) {
     211: 			if (!append)
     212: 				options_array_clear(o);
     213: 			if (options_array_assign(o, value, &cause) != 0) {
     214: 				cmdq_error(item, "%s", cause);
     215: 				free(cause);
     216: 				goto fail;
     217: 			}
     218: 		} else if (options_array_set(o, idx, value, append,
     219: 		    &cause) != 0) {
     220: 			cmdq_error(item, "%s", cause);
     221: 			free(cause);
     222: 			goto fail;
     223: 		}
     224: 	}
     225: 
     226: 	options_push_changes(name);
     227: 
     228: out:
     229: 	free(argument);
     230: 	free(expanded);
     231: 	free(name);
     232: 	return (CMD_RETURN_NORMAL);
     233: 
     234: fail:
     235: 	free(argument);
     236: 	free(expanded);
     237: 	free(name);
     238: 	return (CMD_RETURN_ERROR);
     239: }

