     138: 			return (NULL);
     139: 		memset(nb + buf->size, 0, buf->wpos + len - buf->size);
     140: 		buf->buf = nb;
     141: 		buf->size = buf->wpos + len;
     142: 	}
     143: 
     144: 	b = buf->buf + buf->wpos;
     145: 	buf->wpos += len;
     146: 	return (b);
     147: }

