     545: struct menu_data *
     546: menu_prepare(struct menu *menu, int flags, int starting_choice,
     547:     struct cmdq_item *item, u_int px, u_int py, struct client *c,
     548:     enum box_lines lines, const char *style, const char *selected_style,
     549:     const char *border_style, struct cmd_find_state *fs, menu_choice_cb cb,
     550:     void *data)
     551: {
     552: 	struct menu_data	*md;
     553: 	int			 choice;
     554: 	const char		*name;
     555: 	struct options		*o = c->session->curw->window->options;
     556: 
     557: 	if (c->tty.sx < menu->width + 4 || c->tty.sy < menu->count + 2)
     558: 		return (NULL);
     559: 	if (px + menu->width + 4 > c->tty.sx)
     560: 		px = c->tty.sx - menu->width - 4;
     561: 	if (py + menu->count + 2 > c->tty.sy)
     562: 		py = c->tty.sy - menu->count - 2;
     563: 
     564: 	if (lines == BOX_LINES_DEFAULT)
     565: 		lines = options_get_number(o, "menu-border-lines");
     566: 
>>   567: 	md = xcalloc(1, sizeof *md);
     568: 	md->item = item;
     569: 	md->flags = flags;
     570: 	md->border_lines = lines;
     571: 
     572: 	if (style != NULL)
     573: 		md->style = xstrdup(style);
     574: 	if (selected_style != NULL)
     575: 		md->selected_style = xstrdup(selected_style);
     576: 	if (border_style != NULL)
     577: 		md->border_style = xstrdup(border_style);
     578: 
     579: 	if (fs != NULL)
     580: 		cmd_find_copy_state(&md->fs, fs);
     581: 	screen_init(&md->s, menu->width + 4, menu->count + 2, 0);
     582: 	if (~md->flags & MENU_NOMOUSE)
     583: 		md->s.mode |= (MODE_MOUSE_ALL|MODE_MOUSE_BUTTON);
     584: 	md->s.mode &= ~MODE_CURSOR;
     585: 
     586: 	md->px = px;
     587: 	md->py = py;
     588: 
     589: 	md->menu = menu;
     590: 	md->choice = -1;
     591: 
     592: 	if (md->flags & MENU_NOMOUSE) {
     593: 		if (starting_choice >= (int)menu->count) {
     594: 			starting_choice = menu->count - 1;
     595: 			choice = starting_choice + 1;
     596: 			for (;;) {
     597: 				name = menu->items[choice - 1].name;
     598: 				if (name != NULL && *name != '-') {
     599: 					md->choice = choice - 1;
     600: 					break;
     601: 				}
     602: 				if (--choice == 0)
     603: 					choice = menu->count;
     604: 				if (choice == starting_choice + 1)
     605: 					break;
     606: 			}
     607: 		} else if (starting_choice >= 0) {
     608: 			choice = starting_choice;
     609: 			for (;;) {
     610: 				name = menu->items[choice].name;
     611: 				if (name != NULL && *name != '-') {
     612: 					md->choice = choice;
     613: 					break;
     614: 				}
     615: 				if (++choice == (int)menu->count)
     616: 					choice = 0;
     617: 				if (choice == starting_choice)
     618: 					break;
     619: 			}
     620: 		}
     621: 	}
     622: 
     623: 	md->cb = cb;
     624: 	md->data = data;
     625: 	return (md);
     626: }

