    3778: 	int			 allocated;
    3779: 
    3780: 	while (bufsize < newsize)
    3781: 		bufsize *= 2;
    3782: 	buf = xrealloc(buf, bufsize);
    3783: 
    3784: 	gl = grid_peek_line(gd, py);
    3785: 	if (gl == NULL) {
    3786: 		buf[*size - 1] = '\0';
    3787: 		return (buf);
    3788: 	}
    3789: 	bx = *size - 1;
    3790: 	for (ax = first; ax < last; ax++) {
>>  3791: 		d = window_copy_cellstring(gl, ax, &dlen, &allocated);
    3792: 		newsize += dlen;
    3793: 		while (bufsize < newsize) {
    3794: 			bufsize *= 2;
    3795: 			buf = xrealloc(buf, bufsize);
    3796: 		}
    3797: 		if (dlen == 1)
    3798: 			buf[bx++] = *d;
    3799: 		else {
    3800: 			memcpy(buf + bx, d, dlen);
    3801: 			bx += dlen;
    3802: 		}
>>  3803: 		if (allocated)
    3804: 			free((void *)d);
    3805: 	}
    3806: 	buf[newsize - 1] = '\0';
    3807: 
    3808: 	*size = newsize;
    3809: 	return (buf);
    3810: }

    3813: static void
    3814: window_copy_cstrtocellpos(struct grid *gd, u_int ncells, u_int *ppx, u_int *ppy,
    3815:     const char *str)
    3816: {
    3817: 	u_int			 cell, ccell, px, pywrap, pos, len;
    3818: 	int			 match;
    3819: 	const struct grid_line	*gl;
    3820: 	const char		*d;
    3821: 	size_t			 dlen;
    3822: 	struct {
    3823: 		const char	*d;
    3824: 		size_t		 dlen;
    3825: 		int		 allocated;
    3826: 	} *cells;
    3827: 
    3828: 	/* Populate the array of cell data. */
    3829: 	cells = xreallocarray(NULL, ncells, sizeof cells[0]);
    3830: 	cell = 0;
    3831: 	px = *ppx;
    3832: 	pywrap = *ppy;
    3833: 	gl = grid_peek_line(gd, pywrap);
    3834: 	if (gl == NULL) {
    3835: 		free(cells);
    3836: 		return;
    3837: 	}
    3838: 	while (cell < ncells) {
>>  3839: 		cells[cell].d = window_copy_cellstring(gl, px,
    3840: 		    &cells[cell].dlen, &cells[cell].allocated);
    3841: 		cell++;
    3842: 		px++;
    3843: 		if (px == gd->sx) {
    3844: 			px = 0;
    3845: 			pywrap++;
    3846: 			gl = grid_peek_line(gd, pywrap);
    3847: 			if (gl == NULL)
    3848: 				break;
    3849: 		}
    3850: 	}
    3851: 
    3852: 	/* Locate starting cell. */
    3853: 	cell = 0;
    3854: 	len = strlen(str);
    3855: 	while (cell < ncells) {
    3856: 		ccell = cell;
    3857: 		pos = 0;
    3858: 		match = 1;
    3859: 		while (ccell < ncells) {
    3860: 			if (str[pos] == '\0') {
    3861: 				match = 0;
    3862: 				break;
    3863: 			}
    3864: 			d = cells[ccell].d;
    3865: 			dlen = cells[ccell].dlen;
    3866: 			if (dlen == 1) {
    3867: 				if (str[pos] != *d) {
    3868: 					match = 0;
    3869: 					break;
    3870: 				}
    3871: 				pos++;
    3872: 			} else {
    3873: 				if (dlen > len - pos)
    3874: 					dlen = len - pos;
    3875: 				if (memcmp(str + pos, d, dlen) != 0) {
    3876: 					match = 0;
    3877: 					break;
    3878: 				}
    3879: 				pos += dlen;
    3880: 			}
    3881: 			ccell++;
    3882: 		}
    3883: 		if (match)
    3884: 			break;
    3885: 		cell++;
    3886: 	}
    3887: 
    3888: 	/* If not found this will be one past the end. */
    3889: 	px = *ppx + cell;
    3890: 	pywrap = *ppy;
    3891: 	while (px >= gd->sx) {
    3892: 		px -= gd->sx;
    3893: 		pywrap++;
    3894: 	}
    3895: 
    3896: 	*ppx = px;
    3897: 	*ppy = pywrap;
    3898: 
    3899: 	/* Free cell data. */
    3900: 	for (cell = 0; cell < ncells; cell++) {
    3901: 		if (cells[cell].allocated)
    3902: 			free((void *)cells[cell].d);
    3903: 	}
    3904: 	free(cells);
    3905: }

